import React, { useEffect, useState } from 'react';

const Home = () => {
    const [venues, setVenues] = useState([]);

    useEffect(() => {
        const fetchVenues = async () => {
            try {
                const response = await fetch('/api/venues');
                const data = await response.json();
                setVenues(data);
            } catch (error) {
                console.error('Error fetching venues:', error);
            }
        };

        fetchVenues();
    }, []);

    return (
        <div>
            <h1>Venues</h1>
            <table>
                <thead>
                    <tr>
                        <th>Name</th>
                        <th>Location</th>
                        <th>Capacity</th>
                        <th>Contact</th>
                        <th>Notes</th>
                        <th>Parking</th>
                        <th>Accessibility</th>
                        <th>Owner</th>
                        <th>TCUP Rating</th>
                    </tr>
                </thead>
                <tbody>
                    {venues.map((venue) => (
                        <tr key={venue.id}>
                            <td>{venue.name}</td>
                            <td>{venue.location}</td>
                            <td>{venue.capacity}</td>
                            <td>{venue.contact}</td>
                            <td>{venue.notes}</td>
                            <td>{venue.parking}</td>
                            <td>{venue.accessibility}</td>
                            <td>{venue.owner}</td>
                            <td>{venue.tcup_rating}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default Home;
